using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.RegularExpressions;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;
using OpenAI;

// ---------------------------------------------------------------------------
// Configuration
// ---------------------------------------------------------------------------
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

const string modelId = "gpt-4o-mini-2024-07-18";

// ---------------------------------------------------------------------------
// Service registration
// ---------------------------------------------------------------------------
var services = new ServiceCollection();

services.AddLogging(b => b.AddConsole().SetMinimumLevel(LogLevel.Warning));

services.AddHttpClient("web", c =>
{
    c.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");
    c.Timeout = TimeSpan.FromSeconds(15);
});

services.AddChatClient(b => b
    .UseOpenAIChatClient(modelId, new OpenAIClient(apiKey)));

var sp = services.BuildServiceProvider();

// ---------------------------------------------------------------------------
// Tools
// ---------------------------------------------------------------------------
var notebook = new Notebook();
var httpFactory = sp.GetRequiredService<IHttpClientFactory>();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(
        ([Description("The search query to look up on the web")] string query) =>
            SearchWebAsync(query, httpFactory),
        "SearchWeb",
        "Search the web for information on a topic. Returns a summary of the top results."),

    AIFunctionFactory.Create(
        ([Description("Title or label for the note")] string title,
         [Description("Content of the note to save")] string content) =>
        {
            notebook.Save(title, content);
            return $"Note saved: \"{title}\"";
        },
        "SaveNote",
        "Save a research note for later reference."),

    AIFunctionFactory.Create(
        () => notebook.GetAll(),
        "GetNotes",
        "Retrieve all saved research notes."),
};

// ---------------------------------------------------------------------------
// Agent
// ---------------------------------------------------------------------------
const string instructions = """
    You are a research agent. Your goal is to thoroughly research the topic the
    user provides by searching the web, reading results, and compiling your
    findings into well-organized notes.

    Workflow:
    1. Break the topic into sub-questions.
    2. Use the SearchWeb tool to find information for each sub-question.
    3. Use the SaveNote tool to record key findings as you go.
    4. After completing your research, use GetNotes to review your notes.
    5. Present a final, concise summary of your findings to the user.

    Always cite where information came from when possible.
    """;

var chatClient = sp.GetRequiredService<IChatClient>();
var loggerFactory = sp.GetRequiredService<ILoggerFactory>();

var agent = new ChatClientAgent(
    chatClient,
    instructions: instructions,
    name: "ResearchAgent",
    description: "An agent that researches topics by searching the web and taking notes.",
    tools: tools,
    loggerFactory: loggerFactory,
    services: sp);

agent.ChatOptions = new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 4096,
};

// ---------------------------------------------------------------------------
// Run
// ---------------------------------------------------------------------------
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       🔍  Research Agent  🔍        ║");
Console.WriteLine("╠══════════════════════════════════════╣");
Console.WriteLine("║  Enter a topic to research.         ║");
Console.WriteLine("║  Type 'exit' to quit.               ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();

AgentSession? session = null;

while (true)
{
    Console.ForegroundColor = ConsoleColor.Cyan;
    Console.Write("Topic > ");
    Console.ResetColor();

    var input = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(input))
        continue;
    if (input.Equals("exit", StringComparison.OrdinalIgnoreCase))
        break;

    Console.ForegroundColor = ConsoleColor.DarkGray;
    Console.WriteLine("Researching… (the agent will search the web and take notes)\n");
    Console.ResetColor();

    try
    {
        session ??= await agent.CreateSessionAsync();

        var response = await agent.RunAsync(input, session, cancellationToken: CancellationToken.None);

        Console.ForegroundColor = ConsoleColor.Green;
        Console.WriteLine(response.Text);
        Console.ResetColor();
    }
    catch (Exception ex)
    {
        Console.ForegroundColor = ConsoleColor.Red;
        Console.Error.WriteLine($"Error: {ex.Message}");
        Console.ResetColor();
    }

    Console.WriteLine();
}

// ---------------------------------------------------------------------------
// Web search helper
// ---------------------------------------------------------------------------
static async Task<string> SearchWebAsync(string query, IHttpClientFactory httpFactory)
{
    using var http = httpFactory.CreateClient("web");
    var encoded = WebUtility.UrlEncode(query);

    // Use DuckDuckGo's HTML-lite interface for a simple search.
    var url = $"https://html.duckduckgo.com/html/?q={encoded}";
    try
    {
        var html = await http.GetStringAsync(url);

        // Extract result snippets from the response.
        var results = ParseSearchResults(html);
        if (results.Count == 0)
            return "No results found.";

        var sb = new StringBuilder();
        sb.AppendLine($"Search results for: \"{query}\"\n");
        foreach (var (title, snippet, link) in results.Take(5))
        {
            sb.AppendLine($"- **{title}**");
            sb.AppendLine($"  {snippet}");
            if (!string.IsNullOrEmpty(link))
                sb.AppendLine($"  Source: {link}");
            sb.AppendLine();
        }

        return sb.ToString();
    }
    catch (Exception ex)
    {
        return $"Search failed: {ex.Message}";
    }
}

static List<(string Title, string Snippet, string Link)> ParseSearchResults(string html)
{
    var results = new List<(string, string, string)>();

    // Match DuckDuckGo HTML result blocks.
    var titlePattern = new Regex(
        @"<a[^>]+class=""result__a""[^>]*>(.*?)</a>",
        RegexOptions.Singleline | RegexOptions.IgnoreCase);

    var snippetPattern = new Regex(
        @"<a[^>]+class=""result__snippet""[^>]*>(.*?)</a>",
        RegexOptions.Singleline | RegexOptions.IgnoreCase);

    var linkPattern = new Regex(
        @"<a[^>]+class=""result__url""[^>]*href=""([^""]*?)""",
        RegexOptions.IgnoreCase);

    var titles = titlePattern.Matches(html);
    var snippets = snippetPattern.Matches(html);
    var links = linkPattern.Matches(html);

    for (int i = 0; i < titles.Count && i < 8; i++)
    {
        var title = StripHtml(titles[i].Groups[1].Value).Trim();
        var snippet = i < snippets.Count
            ? StripHtml(snippets[i].Groups[1].Value).Trim()
            : "";
        var link = i < links.Count
            ? WebUtility.UrlDecode(links[i].Groups[1].Value).Trim()
            : "";
        if (!string.IsNullOrWhiteSpace(title))
            results.Add((title, snippet, link));
    }

    return results;
}

static string StripHtml(string html) =>
    Regex.Replace(WebUtility.HtmlDecode(html), "<[^>]+>", "");

// ---------------------------------------------------------------------------
// Notebook — simple in-memory note store
// ---------------------------------------------------------------------------
sealed class Notebook
{
    private readonly List<(string Title, string Content, DateTime Timestamp)> _notes = [];

    public void Save(string title, string content) =>
        _notes.Add((title, content, DateTime.UtcNow));

    public string GetAll()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        var sb = new StringBuilder();
        for (int i = 0; i < _notes.Count; i++)
        {
            var (title, content, ts) = _notes[i];
            sb.AppendLine($"[{i + 1}] {title} ({ts:HH:mm:ss UTC})");
            sb.AppendLine($"    {content}");
            sb.AppendLine();
        }

        return sb.ToString();
    }
}

